create table apex_export_user.templates (
    id                 number
        generated by default as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 start with 1 cache 20 noorder
        nocycle nokeep noscale
    not null enable,
    name               varchar2(255 byte) not null enable,
    content            clob not null enable,
    parent_template_id number,
    created_at         timestamp(6) default systimestamp,
    updated_at         timestamp(6) default systimestamp
);

alter table apex_export_user.templates add primary key ( id )
    using index enable;


